15	
16	/// Non-synthesizable module comparing two AXI channels of the same type
17	module axi_chan_compare #(
18	    /// Ignore ID field if it was remapped
19	    parameter bit  IgnoreId  = 1'b0,
20	    /// Allow reordered responses of different IDs,
21	    /// not compatible with `IgnoreId`
22	    parameter bit  AllowReordering = 1'b0,
23	    /// AXI ID Width
24	    parameter int unsigned IdWidth = 1,
25	    parameter type aw_chan_t = logic,
26	    parameter type w_chan_t  = logic,
27	    parameter type b_chan_t  = logic,
28	    parameter type ar_chan_t = logic,
29	    parameter type r_chan_t  = logic,
30	    parameter type req_t     = logic,
31	    parameter type resp_t    = logic
32	)(
33	    input logic  clk_a_i,
34	    input logic  clk_b_i,
35	    input req_t  axi_a_req,
36	    input resp_t axi_a_res,
37	    input req_t  axi_b_req,
38	    input resp_t axi_b_res
39	);
40	
41	    function automatic void print_aw (
42	        input aw_chan_t aw_expected,
43	        input aw_chan_t aw_received
44	    );
45	        // verilog_lint: waive-start line-length
46	        $display("AW      | expected                                                         | received                                                         ");
47	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
48	        $display("id:     | %64d | %64d", aw_expected.id, aw_received.id);
49	        $display("addr:   | %64x | %64x", aw_expected.addr, aw_received.addr);
50	        $display("len:    | %64d | %64d", aw_expected.len, aw_received.len);
51	        $display("size:   | %64d | %64d", aw_expected.size, aw_received.size);
52	        $display("burst:  | %64d | %64d", aw_expected.burst, aw_received.burst);
53	        $display("lock:   | %64d | %64d", aw_expected.lock, aw_received.lock);
54	        $display("cache:  | %64d | %64d", aw_expected.cache, aw_received.cache);
55	        $display("prot:   | %64d | %64d", aw_expected.prot, aw_received.prot);
56	        $display("qos:    | %64d | %64d", aw_expected.qos, aw_received.qos);
57	        $display("region: | %64d | %64d", aw_expected.region, aw_received.region);
58	        $display("user:   | %64d | %64d", aw_expected.user, aw_received.user);
59	        $display("atop:   | %64d | %64d", aw_expected.atop, aw_received.atop);
60	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
61	        // verilog_lint: waive-stop line-length
62	    endfunction
63	
64	    function automatic void print_ar (
65	        input ar_chan_t ar_expected,
66	        input ar_chan_t ar_received
67	    );
68	        // verilog_lint: waive-start line-length
69	        $display("AR      | expected                                                         | received                                                         ");
70	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
71	        $display("id:     | %64d | %64d", ar_expected.id, ar_received.id);
72	        $display("addr:   | %64x | %64x", ar_expected.addr, ar_received.addr);
73	        $display("len:    | %64d | %64d", ar_expected.len, ar_received.len);
74	        $display("size:   | %64d | %64d", ar_expected.size, ar_received.size);
75	        $display("burst:  | %64d | %64d", ar_expected.burst, ar_received.burst);
76	        $display("lock:   | %64d | %64d", ar_expected.lock, ar_received.lock);
77	        $display("cache:  | %64d | %64d", ar_expected.cache, ar_received.cache);
78	        $display("prot:   | %64d | %64d", ar_expected.prot, ar_received.prot);
79	        $display("qos:    | %64d | %64d", ar_expected.qos, ar_received.qos);
80	        $display("region: | %64d | %64d", ar_expected.region, ar_received.region);
81	        $display("user:   | %64d | %64d", ar_expected.user, ar_received.user);
82	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
83	        // verilog_lint: waive-stop line-length
84	    endfunction
85	
86	    function automatic void print_w (
87	        input w_chan_t w_expected,
88	        input w_chan_t w_received
89	    );
90	        // verilog_lint: waive-start line-length
91	        $display("W       | expected                                                         | received                                                         ");
92	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
93	        $display("data:   | %64x | %64x", w_expected.data, w_received.data);
94	        $display("strb:   | %64d | %64d", w_expected.strb, w_received.strb);
95	        $display("last:   | %64d | %64d", w_expected.last, w_received.last);
96	        $display("user:   | %64d | %64d", w_expected.user, w_received.user);
97	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
98	        // verilog_lint: waive-stop line-length
99	    endfunction
100	
101	    function automatic void print_b (
102	        input b_chan_t b_expected,
103	        input b_chan_t b_received
104	    );
105	        // verilog_lint: waive-start line-length
106	        $display("B       | expected                                                         | received                                                         ");
107	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
108	        $display("id:     | %64d | %64d", b_expected.id, b_received.id);
109	        $display("resp:   | %64d | %64d", b_expected.resp, b_received.resp);
110	        $display("user:   | %64d | %64d", b_expected.user, b_received.user);
111	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
112	        // verilog_lint: waive-stop line-length
113	    endfunction
114	
115	    function automatic void print_r (
116	        input r_chan_t r_expected,
117	        input r_chan_t r_received
118	    );
119	        // verilog_lint: waive-start line-length
120	        $display("R       | expected                                                         | received                                                         ");
121	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
122	        $display("id:     | %64d | %64d", r_expected.id, r_received.id);
123	        $display("data:   | %64x | %64x", r_expected.data, r_received.data);
124	        $display("resp:   | %64d | %64d", r_expected.resp, r_received.resp);
125	        $display("last:   | %64d | %64d", r_expected.last, r_received.last);
126	        $display("user:   | %64d | %64d", r_expected.user, r_received.user);
127	        $display("--------|------------------------------------------------------------------|-----------------------------------------------------------------");
128	        // verilog_lint: waive-stop line-length
129	    endfunction
130	
131	    localparam NumIds = (AllowReordering)? 2**IdWidth : 1;
132	
133	    // queues
134	    aw_chan_t aw_queue [NumIds-1:0][$];
135	    w_chan_t  w_queue              [$];
136	    b_chan_t  b_queue  [NumIds-1:0][$];
137	    ar_chan_t ar_queue [NumIds-1:0][$];
138	    r_chan_t  r_queue  [NumIds-1:0][$];
139	
140	    // requests generated at axi A: enqueue elements
141	    always_ff @(posedge clk_a_i) begin : proc_enqueue_a
142	        // aw
143	        if (axi_a_req.aw_valid & axi_a_res.aw_ready)
144	            if (AllowReordering) aw_queue[axi_a_req.aw.id].push_back(axi_a_req.aw);
145	            else aw_queue[0].push_back(axi_a_req.aw);
146	        // w
147	        if (axi_a_req.w_valid & axi_a_res.w_ready)
148	            w_queue.push_back(axi_a_req.w);
149	        // ar
150	        if (axi_a_req.ar_valid & axi_a_res.ar_ready)
151	            if (AllowReordering) ar_queue[axi_a_req.ar.id].push_back(axi_a_req.ar);
152	            else ar_queue[0].push_back(axi_a_req.ar);
153	    end
154	
155	    // responses generated at axi B: enqueue elements
156	    always_ff @(posedge clk_b_i) begin : proc_enqueue_b
157	        // b
158	        if (axi_b_res.b_valid & axi_b_req.b_ready)
159	            if (AllowReordering) b_queue[axi_b_res.b.id].push_back(axi_b_res.b);
160	            else b_queue[0].push_back(axi_b_res.b);
161	        // r
162	        if (axi_b_res.r_valid & axi_b_req.r_ready)
163	            if (AllowReordering) r_queue[axi_b_res.r.id].push_back(axi_b_res.r);
164	            else r_queue[0].push_back(axi_b_res.r);
165	    end
166	
167	    // requests arriving at axi B from A: dequeue elements and check
168	    always_ff @(posedge clk_b_i) begin : proc_dequeue_and_check_b
169	        // aw
170	        if (axi_b_req.aw_valid & axi_b_res.aw_ready) begin
171	            automatic aw_chan_t aw_exp, aw_recv;
172	            if (AllowReordering) begin
173	                if (aw_queue[axi_b_req.aw.id].size() == 0) $error("AW queue is empty!");
174	                aw_exp = aw_queue[axi_b_req.aw.id].pop_front(); // verilog_lint: waive always-ff-non-blocking
175	            end else begin
176	                if (aw_queue[0].size() == 0) $error("AW queue is empty!");
177	                aw_exp = aw_queue[0].pop_front(); // verilog_lint: waive always-ff-non-blocking
178	            end
179	            aw_recv = axi_b_req.aw;
180	            if (IgnoreId) begin
181	                aw_exp.id = 'X;
182	                aw_recv.id = 'X;
183	            end
184	            if (aw_exp !== aw_recv) begin
185	                $error("AW mismatch!");
186	                print_aw(aw_exp, aw_recv);
187	            end
188	        end
189	        // w
190	        if (axi_b_req.w_valid & axi_b_res.w_ready) begin
191	            automatic w_chan_t w_exp, w_recv;
192	            if (w_queue.size() == 0) $error("W queue is empty!");
193	            w_exp = w_queue.pop_front(); // verilog_lint: waive always-ff-non-blocking
194	            w_recv = axi_b_req.w;
195	            if (w_exp !== w_recv) begin
196	                $error("W mismatch!");
197	                print_w(w_exp, w_recv);
198	            end
199	        end
200	        // ar
201	        if (axi_b_req.ar_valid & axi_b_res.ar_ready) begin
202	            automatic ar_chan_t ar_exp, ar_recv;
203	            if (AllowReordering) begin
204	                if (ar_queue[axi_b_req.ar.id].size() == 0) $error("AR queue is empty!");
205	                ar_exp = ar_queue[axi_b_req.ar.id].pop_front(); // verilog_lint: waive always-ff-non-blocking
206	            end else begin
207	                if (ar_queue[0].size() == 0) $error("AR queue is empty!");
208	                ar_exp = ar_queue[0].pop_front(); // verilog_lint: waive always-ff-non-blocking
209	            end
210	            ar_recv = axi_b_req.ar;
211	            if (IgnoreId) begin
212	                ar_exp.id = 'X;
213	                ar_recv.id = 'X;
214	            end
215	            if (ar_exp !== ar_recv) begin
216	                $error("AR mismatch!");
217	                print_ar(ar_exp, ar_recv);
218	            end
219	        end
220	    end
221	
222	    // responses arriving at axi A from B: dequeue elements and check
223	    always_ff @(posedge clk_a_i) begin : proc_dequeue_and_check_a
224	        // b
225	        if (axi_a_res.b_valid & axi_a_req.b_ready) begin
226	            automatic b_chan_t b_exp, b_recv;
227	            if (AllowReordering) begin
228	                if (b_queue[axi_a_res.b.id].size() == 0) $error("B queue is empty!");
229	                b_exp = b_queue[axi_a_res.b.id].pop_front(); // verilog_lint: waive always-ff-non-blocking
230	            end else begin
231	                if (b_queue[0].size() == 0) $error("B queue is empty!");
232	                b_exp = b_queue[0].pop_front(); // verilog_lint: waive always-ff-non-blocking
233	            end
234	            b_recv = axi_a_res.b;
235	            if (IgnoreId) begin
236	                b_exp.id = 'X;
237	                b_recv.id = 'X;
238	            end
239	            if (b_exp !== b_recv) begin
240	                $error("B mismatch!");
241	                print_b(b_exp, b_recv);
242	            end
243	        end
244	        // r
245	        if (axi_a_res.r_valid & axi_a_req.r_ready) begin
246	            automatic r_chan_t r_exp, r_recv;
247	            if (AllowReordering) begin
248	                if (r_queue[axi_a_res.r.id].size() == 0) $error("R queue is empty!");
249	                r_exp = r_queue[axi_a_res.r.id].pop_front(); // verilog_lint: waive always-ff-non-blocking
250	            end else begin
251	                if (r_queue[0].size() == 0) $error("R queue is empty!");
252	                r_exp = r_queue[0].pop_front(); // verilog_lint: waive always-ff-non-blocking
253	            end
254	            r_recv = axi_a_res.r;
255	            if (IgnoreId) begin
256	                r_exp.id = 'X;
257	                r_recv.id = 'X;
258	            end
259	            if (r_exp !== r_recv) begin
260	                $error("R mismatch!");
261	                print_r(r_exp, r_recv);
262	            end
263	        end
264	    end
265	
266	endmodule : axi_chan_compare
